output.raw_output:
{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "iam_management",
        "action": "modify_roles"
      },
      "depends_on": []
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "workflow_approvals",
        "filter": {
          "status": "approved",
          "metadata.type": "manager_approval"
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "iam_pending_changes",
        "filter": {
          "approval_id": "$2.results.approval_id",
          "status": "ready_for_provisioning"
        }
      },
      "depends_on": [2]
    },
    {
      "tool": "iam.grant_role",
      "arguments": {
        "user_id": "$3.results.user_id",
        "role": "$3.results.new_role",
        "group_memberships": "$3.results.group_memberships"
      },
      "depends_on": [3]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "grant_iam_role",
        "resource": "iam_management",
        "status": "success",
        "details": {
          "user_id": "$3.results.user_id",
          "role_granted": "$3.results.new_role",
          "groups_added": "$3.results.group_memberships",
          "approval_reference": "$2.results.approval_id"
        }
      },
      "depends_on": [4]
    },
    {
      "tool": "mongo.update",
      "arguments": {
        "collection": "iam_pending_changes",
        "filter": {
          "approval_id": "$2.results.approval_id"
        },
        "update": {
          "$set": {
            "status": "provisioned",
            "provisioned_timestamp": "now",
            "provisioned_by": "automation"
          }
        }
      },
      "depends_on": [4]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "update_provisioning_status",
        "resource": "iam_pending_changes",
        "status": "success",
        "details": {
          "approval_id": "$2.results.approval_id",
          "new_status": "provisioned"
        }
      },
      "depends_on": [6]
    },
    {
      "tool": "email.send",
      "arguments": {
        "to": "$3.results.user_email",
        "subject": "IAM Access Provisioning Complete",
        "body": "Your access has been provisioned. Role: $3.results.new_role. Group memberships: $3.results.group_memberships. Approval ID: $2.results.approval_id"
      },
      "depends_on": [7]
    },
